parameters.jsCode:
const ollamaResponse = $input.first().json.message.content;

let turnoData;
try {
  // Intentar parsear JSON directamente
turnoData = JSON.parse(ollamaResponse);
} catch (e) {
  // Buscar JSON entre llaves
const match = ollamaResponse.match(/\{[\s\S]*\}/);
if (match) {
  try {
turnoData = JSON.parse(match[0]);
} catch (e2) {
turnoData = { motivo: ollamaResponse, fecha_preferida: null, horario_preferido: null, medico_preferido: null, tipo_consulta: 'presencial' };
}
  } else {
turnoData = { motivo: ollamaResponse, fecha_preferida: null, horario_preferido: null, medico_preferido: null, tipo_consulta: 'presencial' };
}
}

return [{
  json: {
    motivo: turnoData.motivo || 'consulta',
    fecha_preferida: turnoData.fecha_preferida || null,
    horario_preferido: turnoData.horario_preferido || null,
    medico_preferido: turnoData.medico_preferido || null,
    tipo_consulta: turnoData.tipo_consulta || 'presencial',
    phone: $('Extraer Datos Entrada').first().json.phone,
    profileName: $('Extraer Datos Entrada').first().json.profileName,
    pacienteId: $('Extraer Datos Entrada').first().json.pacienteId
  }
}];

const slotsOcupados = $input.all();
const occupiedTimes = slotsOcupados.map(s => {
  const d = new Date(s.json.fecha_hora);
  return d.getHours() * 60 + d.getMinutes();
});

const slotsDisponibles = [];
// Franjas de 9:00 a 17:00, turnos de 30 min
for (let h = 9; h < 17; h++) {
  for (let m = 0; m < 60; m += 30) {
    const minutos = h * 60 + m;
    if (!occupiedTimes.includes(minutos)) {
      slotsDisponibles.push(`${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}`);
    }
  }
}

return [{
  json: {
    slots: slotsDisponibles.slice(0, 6),
    fecha: $('Extraer JSON Turno').first().json.fecha_preferida,
    motivo: $('Extraer JSON Turno').first().json.motivo,
    tipo_consulta: $('Extraer JSON Turno').first().json.tipo_consulta
  }
}];

